module AssociateTrialComponentResponse =
  struct
    type nonrec t =
      {
      trialComponentArn: TrialComponentArn.t option ;
      trialArn: TrialArn.t option }
    type nonrec error =
      [ `ResourceLimitExceeded of ResourceLimitExceeded.t 
      | `ResourceNotFound of ResourceNotFound.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?trialComponentArn =
      fun ?trialArn -> fun () -> { trialComponentArn; trialArn }
    let error_of_json name json =
      match name with
      | "ResourceLimitExceeded" ->
          `ResourceLimitExceeded (ResourceLimitExceeded.of_json json)
      | "ResourceNotFound" ->
          `ResourceNotFound (ResourceNotFound.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "ResourceLimitExceeded" ->
          `ResourceLimitExceeded (ResourceLimitExceeded.of_xml xml)
      | "ResourceNotFound" -> `ResourceNotFound (ResourceNotFound.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `ResourceLimitExceeded e ->
          `Assoc
            [("error", (`String "ResourceLimitExceeded"));
            ("details", (ResourceLimitExceeded.to_json e))]
      | `ResourceNotFound e ->
          `Assoc
            [("error", (`String "ResourceNotFound"));
            ("details", (ResourceNotFound.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("TrialComponentArn",
           (Option.map x.trialComponentArn ~f:TrialComponentArn.to_value));
        ("TrialArn", (Option.map x.trialArn ~f:TrialArn.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let trialArn =
        (Option.map ~f:TrialArn.of_xml) (Xml.child xml_arg0 "TrialArn") in
      let trialComponentArn =
        (Option.map ~f:TrialComponentArn.of_xml)
          (Xml.child xml_arg0 "TrialComponentArn") in
      make ?trialArn ?trialComponentArn ()
    let of_json json =
      let trialArn = field_map json "TrialArn" TrialArn.of_json in
      let trialComponentArn =
        field_map json "TrialComponentArn" TrialComponentArn.of_json in
      make ?trialArn ?trialComponentArn ()
    let to_json v = composed_to_json to_value v
  end
