module CreateProcessingJobResponse =
  struct
    type nonrec t = {
      processingJobArn: ProcessingJobArn.t }
    type nonrec error =
      [ `ResourceInUse of ResourceInUse.t 
      | `ResourceLimitExceeded of ResourceLimitExceeded.t 
      | `ResourceNotFound of ResourceNotFound.t 
      | `Unknown_operation_error of (string * string option) ]
    let context_ = "CreateProcessingJobResponse"
    let make ~processingJobArn = fun () -> { processingJobArn }
    let error_of_json name json =
      match name with
      | "ResourceInUse" -> `ResourceInUse (ResourceInUse.of_json json)
      | "ResourceLimitExceeded" ->
          `ResourceLimitExceeded (ResourceLimitExceeded.of_json json)
      | "ResourceNotFound" ->
          `ResourceNotFound (ResourceNotFound.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "ResourceInUse" -> `ResourceInUse (ResourceInUse.of_xml xml)
      | "ResourceLimitExceeded" ->
          `ResourceLimitExceeded (ResourceLimitExceeded.of_xml xml)
      | "ResourceNotFound" -> `ResourceNotFound (ResourceNotFound.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `ResourceInUse e ->
          `Assoc
