          (Xml.child_exn ~context:context_ xml_arg0 "S3OutputPath") in
      let localPath =
        (Option.map ~f:DirectoryPath.of_xml) (Xml.child xml_arg0 "LocalPath") in
      make ~s3OutputPath ?localPath ()
    let of_json json =
      let s3OutputPath = field_map_exn json "S3OutputPath" S3Uri.of_json in
      let localPath = field_map json "LocalPath" DirectoryPath.of_json in
      make ~s3OutputPath ?localPath ()
    let to_json v = composed_to_json to_value v
  end
module RuleParameters =
  struct
    type nonrec t = (ConfigKey.t * ConfigValue.t) list
    let make i =
      let open Result in
        ok_or_failwith
          ((check_list_max i ~max:100) >>=
             (fun () -> check_list_min i ~min:0));
        i
    let of_header xs =
      make
        (List.filter_map xs
           ~f:(fun (k, v) ->
                 (Base.String.chop_prefix k ~prefix:"x-amz-meta-") |>
                   (Option.map
                      ~f:(fun chopped ->
                            ((ConfigKey.of_string chopped),
                              (ConfigValue.of_string v))))))
    let to_value xs =
      (xs |>
         (List.map
            ~f:(fun (x, y) ->
                  (ConfigKey.to_value x) |>
                    (fun x -> (ConfigValue.to_value y) |> (fun y -> (x, y))))))
        |> (fun x -> `Map x)
    let to_query v = to_query to_value v
    let of_xml _ =
      failwith "of_xml_converter_of_shape: Map_shape case not implemented"
    let of_json j =
      object_of_json ~key_of_string:ConfigKey.of_string
        ~of_json:ConfigValue.of_json j
    let to_json v = composed_to_json to_value v
  end